import {
  AccountActionsTypes,
  CustomerActionsTypes,
  auth,
  changeVisibleCarousel,
  checkClientType,
  getCustomerData,
  getData,
  getDataAccount,
  getOpenItems,
  getProducts,
  logout,
  refresh,
  refreshToken,
  requestDeviceInfo,
  resumed,
  saveToken,
  updateAccount,
  updateCustomerData,
  updatePassword,
  verifyDevice,
} from '@semparar/mf-app-user';
import { NewVehiclesTypes, getVehicles } from '@semparar/mf-app-vehicles';
import { all, takeLatest, takeLeading } from 'redux-saga/effects';

import { AdditionalCardTypes } from '../ducks/additionalCard';
import { addressTypes } from '../ducks/addressCard';
import { BlockCardTypes } from '../ducks/blockCard';
